def contains_permutation(pattern: str, s: str) -> bool:
    from collections import Counter
    m = len(pattern)
    if m > len(s):
        return False
    need = Counter(pattern)
    have = Counter(s[:m])
    if have == need:
        return True
    for i in range(m, len(s)):
        have[s[i]] += 1
        left_char = s[i - m]
        have[left_char] -= 1
        if have[left_char] == 0:
            del have[left_char]
        if have == need:
            return True
    return False

